svg.script:
(function() {
  var ns = "http://www.w3.org/1999/xhtml";
  var body = document.querySelector("body");

  // Create and inject <head> properly
  var head = document.createElementNS(ns, "head");
  body.prepend(head);

  // Fix document.head and document.body getters
  Object.defineProperty(document, "head", { 
    get: function() { return head; }, 
    configurable: true 
  });
  Object.defineProperty(document, "body", { 
    get: function() { return body; }, 
    configurable: true 
  });

  // Fix createElement to use XHTML namespace
  var origCreate = document.createElement.bind(document);
  document.createElement = function(tag, opts) {
    return document.createElementNS(ns, tag, opts);
  };
})();
